# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.
# Category: path_traversal

package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File
import play.api.http.HttpEntity
import akka.util.ByteString
import akka.stream.scaladsl.StreamConverters
import java.nio.file.{Files, Paths, Path}

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val uploadDir = "uploads"

  def serveFile(filename: String) = Action { implicit request =>
    try {
      val safePath = normalizePath(filename)
      val filePath = s"$uploadDir/$safePath"
      val file = new File(filePath)
      
      if (!file.exists() || !file.isFile) {
        NotFound("File not found")
      } else {
        val canonicalPath = file.getCanonicalPath
        val baseCanonicalPath = new File(uploadDir).getCanonicalPath
        
        if (!canonicalPath.startsWith(baseCanonicalPath)) {
          Forbidden("Access denied")
        } else {
          val source = Source.fromFile(filePath)
          val content = source.mkString
          source.close()
          
          val contentType = Files.probeContentType(Paths.get(filePath)) match {
            case null => "application/octet-stream"
            case ct => ct
          }
          
          Ok(content).as(contentType)
        }
      }
    } catch {
      case e: Exception =>
        InternalServerError(s"Error reading file: ${e.getMessage}")
    }
  }

  def downloadFile(filename: String) = Action { implicit request =>
    try {
      val safePath = normalizePath(filename)
      val filePath = s"$uploadDir/$safePath"
      val file = new File(filePath)
      
      if (!file.exists() || !file.isFile) {
        NotFound("File not found")
      } else {
        val canonicalPath = file.getCanonicalPath
        val baseCanonicalPath = new File(uploadDir).getCanonicalPath
        
        if (!canonicalPath.startsWith(baseCanonicalPath)) {
          Forbidden("Access denied")
        } else {
          val contentType = Files.probeContentType(Paths.get(filePath)) match {
            case null => "application/octet-stream"
            case ct => ct
          }
          
          val fileInputStream = new java.io.FileInputStream(file)
          val dataContent = StreamConverters.fromInputStream(() => fileInputStream)
          
          Ok.sendEntity(
            HttpEntity.Streamed(
              dataContent,
              Some(file.length()),
              Some(contentType)
            )
          ).withHeaders(
            CONTENT_DISPOSITION -> s"""attachment; filename="${file.getName}""""
          )
        }
      }
    } catch {
      case e: Exception =>
        InternalServerError(s"Error downloading file: ${e.getMessage}")
    }
  }

  def serveFileWithSubdir(subdir: String, filename: String) = Action { implicit request =>
    try {
      val safePath = normalizePath(s"$subdir/$filename")
      val filePath = s"$uploadDir/$safePath"
      val file = new File(filePath)
      
      if (!file.exists() || !file.isFile) {
        NotFound("File not found")
      } else {
        val canonicalPath = file.getCanonicalPath
        val baseCanonicalPath = new File(uploadDir).getCanonicalPath
        
        if (!canonicalPath.startsWith(baseCanonicalPath)) {
          Forbidden("Access denied")
        } else {
          val source = Source.fromFile(filePath)
          val content = source.mkString
          source.close()
          
          val contentType = Files.probeContentType(Paths.get(filePath)) match {
            case null => "application/octet-stream"
            case ct => ct
          }
          
          Ok(content).as(contentType)
        }
      }
    } catch {
      case e: Exception =>
        InternalServerError(s"Error reading file: ${e.getMessage}")
    }
  }

  def listFiles(subdir: Option[String] = None) = Action { implicit request =>
    try {
      val dirPath = subdir match {
        case Some(dir) => s"$uploadDir/${normalizePath(dir)}"
        case None => uploadDir
      }
      
      val directory = new File(dirPath)
      
      if (!directory.exists() || !directory.isDirectory) {
        NotFound("Directory not found")
      } else {
        val canonicalPath = directory.getCanonicalPath
        val baseCanonicalPath = new File(uploadDir).getCanonicalPath
        
        if (!canonicalPath.startsWith(baseCanonicalPath)) {
          Forbidden("Access denied")
        } else {
          val files = directory.listFiles().toList.map { file =>
            Map(
              "name" -> file.getName,
              "type" -> (if (file.isDirectory) "directory" else "file"),
              "size" -> file.length().toString,
              "path" -> file.getPath.replace(uploadDir + "/", "")
            )
          }
          
          Ok(play.api.libs.json.Json.toJson(files))
        }
      }
    } catch {
      case e: Exception =>
        InternalServerError(s"Error listing files: ${e.getMessage}")
    }
  }

  private def normalizePath(path: String): String = {
    val normalized = Paths.get(path).normalize().toString
    normalized.replace("\\", "/")
  }
}